INSERT INTO `settings` (`id`, `setting_key`, `setting_value`, `setting_type`, `description`, `created_at`, `updated_at`) VALUES ('162', 'web_destinations', '[{\"id\":\"dest_699bf9d57223e\",\"title\":\"Ben\\u2019s Cafe Karimunjawa\",\"subtitle\":\"The Ultimate Overwater Spot with the Best Sunset Views!\",\"content\":\"Karimunjawa never ceases to amaze. Beyond its world-class underwater beauty, there is a hidden gem for foodies and sunset seekers that must be on your travel itinerary: Ben\\u2019s Cafe.\\r\\n\\r\\nThis isn\'t just your average coffee shop. Ben\\u2019s Cafe offers a unique lounging experience and natural scenery that will make you want to stay forever.\\r\\n\\r\\n\\ud83c\\udf0a Nestled Under the Mountains, Floating Over the Sea\\r\\nHave you ever imagined sipping a drink while floating directly over the ocean, sheltered by the majesty of lush green hills? That is exactly the sensation Ben\\u2019s Cafe provides.\\r\\n\\r\\nThe location is both strategic and iconic, bridging two incredible natural elements: positioned right at the foot of the mountain and built directly over the sea. The rustic wooden design blends seamlessly with the environment. You can feel the fresh sea breeze and listen to the gentle waves lapping beneath your feet. It is pure serenity!\\r\\n\\r\\n\\ud83c\\udf05 The Best Sunset Spot in Karimunjawa\\r\\nIf you are looking for the perfect place to end your day, Ben\\u2019s Cafe is the answer. It is widely known as one of the most stunning sunset spots in the archipelago.\\r\\n\\r\\nAs evening approaches, the sky transforms into a canvas of orange, pink, and gold. Because the cafe sits over the water with an unobstructed view, you get a front-row seat to the sun dipping below the horizon. It is the perfect moment for silhouette photography or simply soaking in the beauty of nature.\\r\\n\\r\\n\\u2615 An Iconic Must-Visit Destination\\r\\nAs one of the most famous spots in Karimunjawa, Ben\\u2019s Cafe is a favorite for both local and international travelers. It\\u2019s the perfect place for:\\r\\n\\r\\nPost-Island Hopping Relaxation: Rest your weary legs after a day of snorkeling with a fresh young coconut or a warm cup of coffee.\\r\\n\\r\\nRomantic Dinners: Enjoy fresh seafood in a dreamy, dimly lit atmosphere over the water.\\r\\n\\r\\nAesthetic Photo Hunting: Every corner of the cafe, with the backdrop of the open sea and rolling hills, is incredibly Instagrammable.\\r\\n\\r\\nConclusion\\r\\nBen\\u2019s Cafe is more than just a place to eat and drink; it is a destination where you can fully immerse yourself in the beauty of Karimunjawa. The combination of blue waters, green hills, and golden sunsets makes this place truly special. Make sure Ben\\u2019s Cafe is on your list when you visit this little piece of paradise in the Java Sea!\",\"image\":\"https:\\/\\/res.cloudinary.com\\/dpdmut9ls\\/image\\/upload\\/v1774618223\\/adf_system\\/destinations\\/dest_dest_699bf9d57223e.jpg\",\"order\":1,\"active\":true},{\"id\":\"dest_699bf8de2b864\",\"title\":\"Bukit Love\",\"subtitle\":\"This tourist destination is easily one of the most captivating spots in Karimunjawa\",\"content\":\"A Paradise for Photography Lovers\\r\\n\\r\\nThis tourist destination is easily one of the most captivating spots in Karimunjawa. Offering breathtaking views of the vast ocean and the pristine, natural ambiance of the Karimunjawa hills, this place is a true haven for nature enthusiasts and photography lovers alike.\\r\\n\\r\\nStanding at an elevation of 150 meters above sea level, you can enjoy spectacular, sweeping views from the hilltop. Once you arrive in Karimunjawa, make sure to visit right away and immerse yourself in the mesmerizing natural charm of Bukit Love.\",\"image\":\"https:\\/\\/res.cloudinary.com\\/dpdmut9ls\\/image\\/upload\\/v1774618325\\/adf_system\\/destinations\\/dest_dest_699bf8de2b864.jpg\",\"order\":2,\"active\":true},{\"id\":\"dest_699c30faa21d9\",\"title\":\"Boby Beach\",\"subtitle\":\"The Golden Sunrise Gateway of Karimunjawa\",\"content\":\"If there is one place that defines a perfect morning in the Karimunjawa tropics, it is undoubtedly Boby Beach (Pantai Boby). While many head to the west for the sunset, seasoned travelers know that the real magic happens at dawn on this stunning eastern coastline.\\r\\n\\r\\n\\ud83c\\udf05 The Best Sunrise Spot in the Archipelago\\r\\nBoby Beach is widely celebrated as the top sunrise destination in Karimunjawa. Thanks to its wide-stretching shoreline facing directly east, visitors are treated to an unobstructed view of the sun emerging from the Java Sea.\\r\\n\\r\\nAs the first light breaks, the sky transforms into a masterpiece of deep purples, fiery oranges, and soft golds, reflecting perfectly off the calm, crystal-clear water.\\r\\n\\r\\n\\ud83c\\udf34 White Sands and Iconic Swings\\r\\nBeyond the sunrise, Boby Beach offers a quintessential tropical vibe:\\r\\n\\r\\nPowdery White Sand: The beach features a broad area of soft, clean sand, perfect for a morning jog or a relaxed picnic.\\r\\n\\r\\nIconic Photo Spots: You will find the famous wooden swings and hammocks set up along the shore. Taking a photo on the swing with the rising sun in the background is a \\\"must-do\\\" for every visitor.\\r\\n\\r\\nLush Coconut Groves: The backdrop of towering coconut trees adds a serene, rustic feel to your morning adventure.\\r\\n\\r\\n\\ud83e\\udd65 A Perfect Start to Your Day\\r\\nThe atmosphere at Boby Beach is remarkably peaceful. Unlike the busier daytime spots, early mornings here offer a sense of solitude. You can enjoy a fresh young coconut from local vendors or simply sit on the sand and listen to the gentle waves. It is the ultimate way to recharge your soul before starting your island-hopping tour.\\r\\n\\r\\n\\ud83d\\udccd Travel Tips:\\r\\nArrival Time: Aim to be there by 5:15 AM to catch the \\\"blue hour\\\" before the actual sunrise.\\r\\n\\r\\nAccessibility: It is easily reachable by motorbike or car from the main town (Karimunjawa village), taking only about 10\\u201315 minutes.\\r\\n\\r\\nPro Tip: After the sunrise, the lighting is perfect for a photoshoot before the tropical sun gets too bright and hot.\",\"image\":\"https:\\/\\/res.cloudinary.com\\/dpdmut9ls\\/image\\/upload\\/v1774619256\\/adf_system\\/destinations\\/dest_dest_699c30faa21d9.jpg\",\"order\":3,\"active\":true},{\"id\":\"dest_69c68d644d32e\",\"title\":\"Discover Tanjung Gelam Beach\",\"subtitle\":\"Karimunjawa\\u2019s Iconic Leaning Coconut Tree & Sunset Paradise\",\"content\":\"If you are hunting for the ultimate tropical postcard in Indonesia, look no further than Tanjung Gelam Beach (Pantai Tanjung Gelam). Nestled on the main island of the breathtaking Karimunjawa archipelago, this pristine stretch of white sand is a mandatory stop for any island-hopper.\\r\\n\\r\\nWhile the crystal-clear turquoise waters and powdery sand are stunning on their own, Tanjung Gelam holds a unique natural treasure that has taken social media by storm: the iconic Leaning Coconut Tree (Spot Kelapa Miring).\\r\\n\\r\\nThe Iconic \\\"Kelapa Miring\\\" Photo Spot\\r\\nThe true star of Tanjung Gelam is a single coconut tree that defies gravity, leaning gracefully outward over the white sand and gently lapping waves. This natural marvel creates a picture-perfect frame that embodies the ultimate tropical getaway.\\r\\n\\r\\nThe Perfect Pose: Visitors love to climb halfway up the curved trunk, sit comfortably, and pose with the vast ocean as their backdrop.\\r\\n\\r\\nA Photographer\'s Dream: Whether you are shooting with a professional camera or a smartphone, the contrast between the green palm fronds, the stark white beach, and the azure sea guarantees an unforgettable, Instagram-worthy shot.\\r\\n\\r\\nWhy Tanjung Gelam is a Must-Visit Destination\\r\\nBeyond the famous photo spot, Tanjung Gelam offers an unforgettable beach experience:\\r\\n\\r\\nThe Ultimate Sunset Destination: Tanjung Gelam is widely considered the best sunset spot in Karimunjawa. Because the beach faces west, it offers an unobstructed view of the sun melting into the Java Sea, painting the sky in vibrant shades of orange, pink, and purple.\\r\\n\\r\\nCalm, Shallow Waters: The waves here are incredibly gentle, making it a safe and relaxing spot for swimming, wading, or simply floating in the crystal-clear water.\\r\\n\\r\\nAuthentic Local Vibes: The beach is lined with small, traditional wooden stalls (warungs). After a long day of snorkeling, nothing beats sitting on the beach with a fresh young coconut (es kelapa muda) and a plate of hot, crispy fried bananas (pisang goreng) while waiting for the golden hour.\\r\\n\\r\\nHow to Get There\\r\\nTanjung Gelam is highly accessible, making it a convenient addition to any Karimunjawa itinerary:\\r\\n\\r\\nBy Sea: It is almost always the final stop on standard island-hopping and snorkeling boat tours. Boats usually dock here in the late afternoon, perfectly timed for the sunset.\\r\\n\\r\\nBy Land: If you prefer to explore at your own pace, you can easily reach the beach by renting a scooter or car from the main town square (Alun-Alun Karimunjawa). The ride takes about 15 to 20 minutes through lush, scenic coastal roads.\\r\\n\\r\\nQuick Tips for Visitors\\r\\nBest Time to Visit: Arrive around 4:00 PM to secure a good spot, take photos at the leaning coconut tree while the light is soft, and stay for the sunset at 5:30 PM.\\r\\n\\r\\nWhat to Bring: Sunscreen, a camera\\/smartphone with a waterproof pouch, cash for local snacks, and insect repellent for the early evening.\",\"image\":\"https:\\/\\/res.cloudinary.com\\/dpdmut9ls\\/image\\/upload\\/v1774620011\\/adf_system\\/destinations\\/dest_dest_69c68d644d32e.jpg\",\"order\":5,\"active\":true}]', 'text', 'Website Destinations', '2026-02-23 13:51:10', '2026-03-27 21:09:27');
