INSERT INTO `settings` (`id`, `setting_key`, `setting_value`, `setting_type`, `description`, `created_at`, `updated_at`) VALUES ('433', 'web_activities', '[{\"id\":\"snorkeling\",\"eyebrow\":\"Underwater World\",\"title\":\"Snorkelling in Crystal-Clear Waters\",\"image\":\"https:\\/\\/res.cloudinary.com\\/dpdmut9ls\\/image\\/upload\\/v1774512079\\/adf_system\\/activities\\/act_snorkeling.jpg\",\"body\":\"Karimunjawa\'s waters are among the clearest in the entire Java Sea, with visibility regularly reaching <strong>15 to 20 metres<\\/strong> on calm days. Just a short boat ride from Narayana, you\'ll be floating above vibrant coral gardens teeming with life \\u2014 clownfish darting between anemones, parrotfish grazing on coral, giant clams wedged into reef crevices, and green sea turtles gliding through the blue. The archipelago\'s most celebrated snorkelling spots include <strong>Menjangan Kecil<\\/strong>, <strong>Gosong Cemara<\\/strong>, and <strong>Taka Menyawakan<\\/strong>. The marine biodiversity here is extraordinary \\u2014 over 240 species of coral and more than 240 species of reef fish have been recorded within Karimunjawa National Marine Park.\",\"details\":[\"Best time: 7:00\\u201311:00 (calmest water, best visibility)\",\"Top spots: Menjangan Kecil, Gosong Cemara, Taka Menyawakan\",\"Distance from hotel: 10\\u201330 min by boat\",\"Suitable for all ages and skill levels\",\"Equipment rental available on most boat trips\",\"Over 240 coral species and 240+ fish species recorded\"],\"order\":1,\"active\":true},{\"id\":\"island-hopping\",\"eyebrow\":\"Island Exploration\",\"title\":\"Hopping Between 27 Islands\",\"image\":\"https:\\/\\/res.cloudinary.com\\/dpdmut9ls\\/image\\/upload\\/v1774621129\\/adf_system\\/activities\\/act_island-hopping.jpg\",\"body\":\"The Karimunjawa archipelago comprises <strong>27 islands<\\/strong>, and only five of them are inhabited \\u2014 the rest remain wild, forested, and fringed by powdery white sand. An island-hopping trip is the quintessential Karimunjawa experience. <strong>Cemara Kecil<\\/strong> is famous for its iconic leaning coconut palm. <strong>Menjangan Besar<\\/strong> has a hilltop viewpoint and a shark conservation area. Most tours last a full day and include stops at 3\\u20135 islands, a freshly grilled seafood lunch on the beach, and plenty of time to snorkel, swim, or simply sit on a deserted shore.\",\"details\":[\"Full-day excursion (08:00\\u201316:00)\",\"Visit 3\\u20135 islands per trip\",\"Popular stops: Cemara Kecil, Cemara Besar, Menjangan Besar, Geleang\",\"Grilled seafood lunch included on most trips\",\"Customisable routes available for private charters\",\"Bring sunscreen, hat, and waterproof bag\"],\"order\":2,\"active\":true},{\"id\":\"diving\",\"eyebrow\":\"Deep Exploration\",\"title\":\"Scuba Diving the Marine National Park\",\"image\":\"https:\\/\\/res.cloudinary.com\\/dpdmut9ls\\/image\\/upload\\/v1774512300\\/adf_system\\/activities\\/act_diving.jpg\",\"body\":\"Karimunjawa has been a <strong>National Marine Park<\\/strong> since 2001. Below the surface you\'ll find towering sea fans, dense staghorn coral, barrel sponges, and astonishing marine life. Divers regularly encounter <strong>blacktip and whitetip reef sharks<\\/strong>, Napoleon wrasse, schools of barracuda, and on lucky days \\u2014 <strong>whale sharks<\\/strong>. Top sites include wall dives at <strong>Taka Malang<\\/strong>, the wreck at <strong>Kapal Tenggelam<\\/strong> (patrol vessel at 25m), and the coral gardens of <strong>Pulau Sintok<\\/strong>.\",\"details\":[\"Over 30 mapped dive sites\",\"Depth range: 5\\u201340+ metres\",\"Marine life: reef sharks, Napoleon wrasse, sea turtles, whale sharks (seasonal)\",\"Top sites: Taka Malang, Kapal Tenggelam wreck, Pulau Sintok\",\"PADI courses: DSD, Open Water, Advanced\",\"Best visibility: April\\u2013September\",\"Water temperature: 27\\u201330\\u00b0C year-round\"],\"order\":3,\"active\":true},{\"id\":\"shark-encounter\",\"eyebrow\":\"Wildlife Encounter\",\"title\":\"Swimming with Sharks & Rays\",\"image\":\"https:\\/\\/images.unsplash.com\\/photo-1560275619-4662e36fa65c?w=900&q=80\",\"body\":\"At <strong>Menjangan Besar Island<\\/strong>, a natural ocean enclosure allows visitors to swim alongside <strong>blacktip reef sharks and giant stingrays<\\/strong>. This community-run conservation initiative has local fishermen partnering with the national park to protect juvenile sharks. You wade into chest-deep water while reef sharks circle with calm, elegant movements. The experience is both exhilarating and surprisingly peaceful. Guides are always present, making it safe even for children.\",\"details\":[\"Location: Menjangan Besar Island (15 min by boat)\",\"Species: Blacktip reef sharks & giant stingrays\",\"Safe for children under adult supervision\",\"Community-run conservation initiative\",\"Entrance fee supports local shark protection\",\"Waterproof camera highly recommended\"],\"order\":4,\"active\":false},{\"id\":\"sunset\",\"eyebrow\":\"Golden Hour\",\"title\":\"Watching the Sunset from Ben\'s Cafe\",\"image\":\"https:\\/\\/res.cloudinary.com\\/dpdmut9ls\\/image\\/upload\\/v1774515224\\/adf_system\\/activities\\/act_sunset.jpg\",\"body\":\"Karimunjawa faces west across the open Java Sea \\u2014 <strong>the sunsets are extraordinary<\\/strong>. The most famous viewpoint is <strong>Bukit Love<\\/strong> (Love Hill) with its heart-shaped sign framing the horizon. The walk up takes about 10 minutes. Another popular spot is <strong>Legon Lele<\\/strong> beach. For something special, consider a <strong>sunset boat cruise<\\/strong> on a traditional wooden boat.\",\"details\":[\"Bukit Love: 10 min walk\\/ride from most hotels\",\"Sunset time: ~17:15\\u201317:45 depending on season\",\"Alternative spots: Legon Lele beach, Sunset Pier, boat cruise\",\"Best from April\\u2013October (dry season)\",\"Free access to all hilltop viewpoints\"],\"order\":5,\"active\":true},{\"id\":\"mangrove\",\"eyebrow\":\"Nature & Conservation\",\"title\":\"Exploring the Mangrove Forest Trail\",\"image\":\"https:\\/\\/res.cloudinary.com\\/dpdmut9ls\\/image\\/upload\\/v1774621131\\/adf_system\\/activities\\/act_mangrove.jpg\",\"body\":\"The <strong>Mangrove Tracking Area<\\/strong> near Kemujan features a well-maintained wooden boardwalk through dense mangrove forest. The canopy is alive with <strong>kingfishers<\\/strong>, <strong>white-bellied sea eagles<\\/strong>, and the rare mangrove pitta. For a more immersive experience, explore the channels <strong>by kayak<\\/strong>, paddling silently through shaded waterways. 15+ mangrove species have been identified in the park.\",\"details\":[\"Location: Mangrove Tracking Area, near Kemujan\",\"Duration: 1\\u20132 hours (walk) or 2\\u20133 hours (kayak)\",\"Wooden boardwalk suitable for all fitness levels\",\"Best visited early morning (cooler, more wildlife)\",\"Kayak rentals available on-site\",\"Birdlife: kingfishers, sea eagles, herons, mangrove pittas\"],\"order\":6,\"active\":true},{\"id\":\"motorbike\",\"eyebrow\":\"Freedom to Roam\",\"title\":\"Exploring the Island by Motorbike\",\"image\":\"https:\\/\\/res.cloudinary.com\\/dpdmut9ls\\/image\\/upload\\/v1774741193\\/adf_system\\/activities\\/act_motorbike.png\",\"body\":\"The best way to discover Karimunjawa at your own pace is on a <strong>motorbike<\\/strong>. Ride through <strong>traditional fishing villages<\\/strong>, stop at a roadside <strong>warung<\\/strong> for grilled fish and sambal, or follow a dirt track to a hidden viewpoint. The <strong>west coast<\\/strong> road passes a string of secluded beaches. The <strong>eastern road to Kemujan<\\/strong> crosses a narrow bridge between islands through mangrove-lined channels.\",\"details\":[\"Scooter rental: ~IDR 75,000\\u2013100,000 per day\",\"Main roads paved and well-maintained\",\"Helmets provided with rental\",\"Recommended: West coast beach road + Kemujan bridge\",\"Full island circuit: ~2\\u20133 hours with stops\"],\"order\":7,\"active\":true},{\"id\":\"fishing\",\"eyebrow\":\"Ocean Tradition\",\"title\":\"Traditional & Sport Fishing\",\"image\":\"https:\\/\\/images.unsplash.com\\/photo-1544551763-46a013bb70d5?w=900&q=80\",\"body\":\"Join a <strong>traditional fishing trip<\\/strong> on a wooden boat alongside experienced local fishermen. The waters are rich with <strong>snapper, grouper, trevally, barracuda, and tuna<\\/strong>. For something exciting, try <strong>night fishing (mancing malam)<\\/strong>: head out after sunset, fish by lamplight under the Milky Way while the crew grills your earlier catch over charcoal on the back of the boat.\",\"details\":[\"Traditional fishing: half-day trips from harbour\",\"Species: snapper, grouper, trevally, barracuda, tuna, GT\",\"Night fishing: depart ~18:00, return by 22:00\",\"No experience necessary \\u2014 local guides teach you\",\"Catch can be grilled on the boat\",\"Best fishing months: March\\u2013October\"],\"order\":8,\"active\":true},{\"id\":\"kayaking\",\"eyebrow\":\"Coastal Adventure\",\"title\":\"Kayaking & Stand-Up Paddleboarding\",\"image\":\"https:\\/\\/images.unsplash.com\\/photo-1472745433479-4556f22e32c2?w=900&q=80\",\"body\":\"Karimunjawa\'s calm, sheltered bays are ideal for <strong>kayaking and SUP<\\/strong>. Paddle along the coastline over coral gardens visible through transparent water. The <strong>mangrove channels<\\/strong> on the eastern side offer a quiet, meditative journey. For SUP, the <strong>shallow lagoon near Cemara Kecil<\\/strong> is a dream \\u2014 paddle over white sand and turquoise water so clear it feels like floating on air.\",\"details\":[\"Best conditions: morning before 11:00\",\"Kayak rental: ~IDR 50,000\\u201375,000\\/hour\",\"SUP rental: ~IDR 75,000\\u2013100,000\\/hour\",\"Top routes: mangrove channels, Cemara Kecil lagoon\",\"No experience needed for calm-water paddling\",\"Suitable for ages 8 and up\"],\"order\":9,\"active\":true},{\"id\":\"trekking\",\"eyebrow\":\"Highland Adventure\",\"title\":\"Jungle Trekking & Hill Walks\",\"image\":\"https:\\/\\/images.unsplash.com\\/photo-1551632811-561732d1e306?w=900&q=80\",\"body\":\"The interior of the main island is covered in dense <strong>tropical lowland forest<\\/strong>. The <strong>Bukit Gajah trail<\\/strong> passes the rare <em>Dewadaru<\\/em> tree (sacred, found almost nowhere else) and endemic <strong>Karimunjawa white-eye<\\/strong> bird (critically endangered). The summit offers a <strong>360-degree panorama<\\/strong> over the entire archipelago.\",\"details\":[\"Trail options: 30 min easy to 3\\u20134 hour challenging\",\"Highlights: Dewadaru sacred tree, endemic bird species\",\"Bukit Gajah: moderate difficulty, panoramic summit views\",\"Guides available through National Park office\",\"Bring: water, closed shoes, insect repellent\"],\"order\":10,\"active\":false},{\"id\":\"beach-camping\",\"eyebrow\":\"Under the Stars\",\"title\":\"Camping on Uninhabited Islands\",\"image\":\"https:\\/\\/images.unsplash.com\\/photo-1504280390367-361c6d9f38f4?w=900&q=80\",\"body\":\"Spend a night <strong>camping on an uninhabited island<\\/strong>. Popular islands include <strong>Cemara Besar<\\/strong> and <strong>Geleang<\\/strong>. Local operators arrange everything: boat transfer, tents, sleeping mats, and a crew who grills fresh fish over an open fire. The <strong>Milky Way<\\/strong> arcs overhead with astonishing clarity \\u2014 zero light pollution.\",\"details\":[\"Popular islands: Cemara Besar, Geleang, Menjangan Kecil\",\"Duration: overnight or extended (2 nights)\",\"All equipment provided: tents, mats, cooking gear\",\"Fresh seafood dinner by local crew\",\"Zero light pollution \\u2014 exceptional stargazing\",\"Best during dry season: April\\u2013October\"],\"order\":11,\"active\":true},{\"id\":\"village-culture\",\"eyebrow\":\"Local Heritage\",\"title\":\"Village Tours & Local Culture\",\"image\":\"https:\\/\\/images.unsplash.com\\/photo-1590523741831-ab7e8b8f9c7f?w=900&q=80\",\"body\":\"Visit <strong>Karimunjawa Village<\\/strong> \\u2014 walk through narrow lanes past traditional wooden houses, visit the <strong>historic cemetery of Sunan Nyamplungan<\\/strong> (15th century Islamic missionary), and watch traditional boatbuilders at work. The <strong>Bugis community in Kemujan<\\/strong> maintains distinct cultural traditions. Try local cuisine: <strong>nasi goreng ikan<\\/strong>, <strong>sate kelapa<\\/strong>, and <strong>bakso ikan<\\/strong>.\",\"details\":[\"Karimunjawa Village: walking distance from harbour\",\"Sunan Nyamplungan: historic Islamic heritage site\",\"Bugis community in Kemujan\",\"Traditional boatbuilding at main harbour\",\"Local cuisine: nasi goreng ikan, sate kelapa, bakso ikan\",\"Best with a local guide (arranged via hotel)\"],\"order\":12,\"active\":false}]', 'text', 'Website Activities', '2026-03-26 00:59:54', '2026-03-29 06:40:59');
