INSERT INTO `settings` (`id`, `setting_key`, `setting_value`, `setting_type`, `description`, `created_at`, `updated_at`) VALUES ('505', 'breakfast_wa_info_text', 'Hai Kak, berikut untuk pilihan menu breakfast Narayana Resort Karimunjawa. Setiap kamar mendapatkan 2 makanan dan 2 minuman breakfast.\r\nBreakfast sudah termasuk Jus dan Buah.\r\n\r\nBreakfast berada di Hunger Resto (samping Pool) mulai jam 7 sampai 10 pagi, bisa informasikan ke kami breakfast berkenan di siapkan jam berapa ya Kak..\r\n\r\nJika ada Tambahan breakfast 75.500/pax (include PPN)\r\n\r\nMohon konfirmasi menu sebelum jam 9 malam\r\n\r\nTerimakasih \r\nFront Office', 'string', NULL, '2026-04-24 13:27:44', '2026-04-25 22:01:17');
